def perceive(data):
    if not isinstance(data, dict):
        return {}

    def read(*keys):
        for k in keys:
            if k in data and data[k] is not None:
                return float(data[k])
        return None

    out = {}
    hr = read("heart_rate", "hr", "pulse")
    if hr is not None:
        out["heart_rate"] = round(hr, 2)
    rr = read("resp_rate", "rr", "respiratory_rate")
    if rr is not None:
        out["resp_rate"] = round(rr, 2)
    t = read("temp_c", "temp", "temperature")
    if t is not None:
        out["temp_c"] = round(t, 2)
    bp = read("sys_bp", "sbp", "systolic")
    if bp is not None:
        out["sys_bp"] = round(bp, 2)
    lac = read("lactate")
    if lac is not None:
        out["lactate"] = round(lac, 2)
    return out
